package com.example.demo.models;import jakarta.persistence.*;import lombok.*;import java.time.LocalDateTime;
@Entity @Table(name="auditoria") @Getter @Setter @NoArgsConstructor @AllArgsConstructor @Builder public class Auditoria{@Id @GeneratedValue(strategy=GenerationType.IDENTITY)private Long id;@Column(nullable=false)private LocalDateTime fecha;@ManyToOne(fetch=FetchType.LAZY)@JoinColumn(name="usuario_id")private Persona usuario;@Column(nullable=false)private String accion;@Column(nullable=false)private String entidad;@Column(name="entidad_id")private String entidadId;private String detalle;private String ip;}
